SELECT id, name, city FROM stores WHERE city='Graz';

SELECT sku, path, brand, series, model, name, properties
FROM products
WHERE model IN ('1ZE-TCR','214-ZHY','1OW-IK5','106-TS1','1VG-P5G','37H-N9K')
ORDER BY model
LIMIT 50;

WITH actor AS (
  SELECT id, store_id FROM employees WHERE id='emp_041'
), cust AS (
  SELECT id, email FROM customers WHERE email='christoph.adler+cust656@fastmail.com'
)
SELECT a.id AS actor_id, a.store_id AS actor_store_id, c.id AS customer_id, c.email
FROM actor a CROSS JOIN cust c;
